external_knowledge:
; 'voyages' metaphorically refers to the number of matches a team has played;
'conquered lands' (wins) represents matches with a final score greater than zero;
'lost territories' (losses) represents matches with a final score less than zero;
'stable alliances' (draws) represents matches with a final score equal to zero;

sql:
SELECT home_team, away_team
FROM matches
ORDER BY match_date DESC;

SELECT DISTINCT s.stadium_name 
FROM stadiums s 
JOIN matches m ON s.stadium_id = m.stadium_id;

SELECT AVG(home_goals) AS average_home_goals
FROM matches
WHERE league = 'E Div 2' AND match_date BETWEEN '2020-08-01' AND '2021-05-31';

SELECT SUM(home_goals + away_goals) AS total_goals
FROM matches
WHERE league = 'E Div 2' AND match_date BETWEEN '1954-01-01' AND '1954-12-31';

SELECT AVG(home_goals + away_goals) AS average_goals
FROM matches
WHERE league = 'Premier League';

SELECT COUNT(*) AS total_matches
FROM matches
WHERE league = 'Premier League' AND match_date LIKE '2022-%';

SELECT AVG(home_goals + away_goals) AS average_goals
FROM matches
WHERE league = 'E Div 2';

SELECT SUM(home_goals + away_goals) AS total_goals
FROM matches
WHERE league = 'E Div 1';

SELECT (home_goals + away_goals) AS total_goals
FROM matches
WHERE match_id = 1;
